const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');

const packageDefinition = protoLoader.loadSync('path/to/your/service.proto', {
  keepCase: true,
  longs: String,
  enums: String,
  defaults: true,
  oneofs: true
});

const yourService = grpc.loadPackageDefinition(packageDefinition).your.service;

function createClient(host, credentials) {
  return new yourService.YourService(host, credentials);
}

async function forwardHeadersToGrpc(userHeaders, backendHost, backendPort, serviceName, methodName) {
  const client = createClient(`${backendHost}:${backendPort}`, grpc.credentials.createInsecure());

  const metadata = new grpc.Metadata();
  for (const [key, value] of Object.entries(userHeaders)) {
    if (['user-agent', 'x-forwarded-for'].includes(key.toLowerCase()) || key.startsWith('x-')) {
      metadata.add(key, value);
    }
  }

  try {
    const call = client[methodName](metadata);
    return new Promise((resolve, reject) => {
      call.on('data', (response) => resolve(response));
      call.on('error', (err) => reject(err));
      call.on('end', () => call.emit('data', null)); // Ensure the promise is resolved if no data is received
    });
  } catch (error) {
    console.error('Error forwarding headers to gRPC:', error);
    throw error;
  }
}

